```

#### 2.7 `packages/generator-rest-client/src/generator.ts`

This is the core generation logic. It receives `GeneratorOptions`, iterates over the DMMF, and writes a `rest-client.ts` file.

**Function signature:**

```typescript
import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator-helper'

import {
  generateClientClass,
  generateEnumType,
  generateModelCrudMethods,
  generateModelInterfaces,
  generatePreamble,
  mapPrismaScalarToTypeScript,
} from './template'

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value ?? './generated/rest-client'
  const dmmf = options.dmmf

  const lines: string[] = []

  // 1. Preamble (comments, base types)
  lines.push(generatePreamble())

  // 2. Enums
  for (const enumDef of dmmf.datamodel.enums) {
    lines.push(generateEnumType(enumDef))
  }

  // 3. Model interfaces and input types
  for (const model of dmmf.datamodel.models) {
    lines.push(generateModelInterfaces(model))
  }

  // 4. CRUD method types per model
  for (const model of dmmf.datamodel.models) {
    lines.push(generateModelCrudMethods(model))
  }

  // 5. RestClient class
  lines.push(generateClientClass(dmmf.datamodel.models))

  // Write output
  const outputPath = path.resolve(outputDir, 'rest-client.ts')
  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(outputPath, lines.join('\n\n'))
}

export { onGenerate as generateRestClient }
```

**Key logic details:**

- **Output path resolution**: `options.generator.output` is an `EnvValue` (from `/packages/generator/src/configuration.ts` line 28). By the time the external generator receives it, Prisma has already resolved it to an absolute path (see `/packages/internals/src/get-generators/getGenerators.ts` lines 175-198). We access `.value` directly.
- **Filtering relation fields**: When generating interfaces, only fields where `field.kind === 'scalar'` or `field.kind === 'enum'` are included. Fields with `field.kind === 'object'` are relations and must be excluded.
- **Identifying auto-generated fields for CreateInput**: Fields excluded from `CreateInput` are those where `field.hasDefaultValue === true` (auto-increment IDs, `@default(now())` timestamps, UUIDs, etc.) OR `field.isGenerated === true` OR `field.isUpdatedAt === true`. These fields should be made optional in `CreateInput` rather than entirely excluded, so users can still provide them explicitly.
- **Identifying unique fields for WhereUniqueInput**: Fields where `field.isId === true` or `field.isUnique === true`. Also consider `model.primaryKey` for composite IDs (the `primaryKey.fields` array lists the field names).

#### 2.8 `packages/generator-rest-client/src/template.ts`

String template helpers for code generation. Each function returns a string of TypeScript code.

**Type mapping function:**

```typescript
export function mapPrismaScalarToTypeScript(prismaType: string): string {
  const map: Record<string, string> = {
    String: 'string',
    Int: 'number',
    Float: 'number',
    Boolean: 'boolean',
    DateTime: 'string',
    BigInt: 'string',
    Decimal: 'string',
    Json: 'unknown',
    Bytes: 'string',
  }
  return map[prismaType] ?? 'unknown'
}
```

**Preamble generator:**

```typescript
export function generatePreamble(): string {
  return `// Generated by @prisma/generator-rest-client — DO NOT EDIT

type RequestOptions = {
  headers?: Record<string, string>
  signal?: AbortSignal
}

type RestClientConfig = {
  baseUrl: string
  headers?: Record<string, string>
  fetch?: typeof globalThis.fetch
}`
}
```

**Enum generator (using string union types for better ergonomics):**

```typescript
import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

export function generateEnumType(enumDef: DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}
```

**Model interface generator:**

For each model, generates four types:

```typescript
export function generateModelInterfaces(model: Model): string {
  const scalarFields = model.fields.filter(
    (f) => f.kind === 'scalar' || f.kind === 'enum'
  )

  // Main interface — all scalar/enum fields
  const mainInterface = generateInterface(model.name, scalarFields, false)

  // CreateInput — auto-generated fields are optional
  const createFields = scalarFields.map((f) => ({
    ...f,
    isRequired: isAutoGenerated(f) ? false : f.isRequired,
  }))
  const createInterface = generateInterface(
    `${model.name}CreateInput`,
    createFields,
    false
  )

  // UpdateInput — all fields optional, exclude id fields
  const updateFields = scalarFields.filter((f) => !f.isId)
  const updateInterface = generateInterface(
    `${model.name}UpdateInput`,
    updateFields,
    true
  )

  // WhereUniqueInput — only id and unique fields
  const uniqueFields = scalarFields.filter((f) => f.isId || f.isUnique)
  const whereUniqueInterface = generateInterface(
    `${model.name}WhereUniqueInput`,
    uniqueFields,
    false
  )

  return [mainInterface, createInterface, updateInterface, whereUniqueInterface].join('\n\n')
}
```

Where `generateInterface` is a helper:

```typescript
function generateInterface(
  name: string,
  fields: ReadonlyArray<Field>,
  allOptional: boolean
): string {
  const lines = fields.map((f) => {
    const tsType = resolveFieldType(f)
    const optional = allOptional || !f.isRequired
    const list = f.isList ? '[]' : ''
    return `  ${f.name}${optional ? '?' : ''}: ${tsType}${list}`
  })
  return `export interface ${name} {\n${lines.join('\n')}\n}`
}

function resolveFieldType(field: Field): string {
  if (field.kind === 'enum') {
    return field.type // references the generated enum type alias
  }
  return mapPrismaScalarToTypeScript(field.type)
}

function isAutoGenerated(field: Field): boolean {
  return field.hasDefaultValue || field.isGenerated === true || field.isUpdatedAt === true
}
```

**CRUD method type generator (per model):**

Generates a TypeScript interface for the delegate object that handles each model's operations:

```typescript
export function generateModelCrudMethods(model: Model): string {
  const name = model.name
  const lowerName = name.charAt(0).toLowerCase() + name.slice(1)
  const pluralPath = `${lowerName}s` // naive pluralization; REST convention

  return `export interface ${name}Delegate {
  findMany(options?: RequestOptions): Promise<${name}[]>
  findUnique(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name} | null>
  create(data: ${name}CreateInput, options?: RequestOptions): Promise<${name}>
  update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}>
  delete(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}>
}`
}
```

**Client class generator:**

```typescript
export function generateClientClass(models: ReadonlyArray<Model>): string {
  const properties = models.map((m) => {
    const name = m.name
    const lowerName = name.charAt(0).toLowerCase() + name.slice(1)
    const pluralPath = `${lowerName}s`
    return { name, lowerName, pluralPath, delegateType: `${name}Delegate` }
  })

  const propertyDeclarations = properties
    .map((p) => `  readonly ${p.lowerName}: ${p.delegateType}`)
    .join('\n')

  const constructorAssignments = properties
    .map((p) => generateDelegateImplementation(p))
    .join('\n\n')

  return `export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>
  #fetch: typeof globalThis.fetch

${propertyDeclarations}

  constructor(config: RestClientConfig) {
    this.#baseUrl = config.baseUrl.replace(/\\/$/, '')
    this.#headers = config.headers ?? {}
    this.#fetch = config.fetch ?? globalThis.fetch.bind(globalThis)

${constructorAssignments}
  }

  async #request<T>(method: string, path: string, body?: unknown, options?: RequestOptions): Promise<T> {
    const response = await this.#fetch(\`\${this.#baseUrl}\${path}\`, {
      method,
      headers: {
        'Content-Type': 'application/json',
        ...this.#headers,
        ...options?.headers,
      },
      body: body ? JSON.stringify(body) : undefined,
      signal: options?.signal,
    })
    if (!response.ok) {
      throw new Error(\`REST client error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }
}`
}
```

Where `generateDelegateImplementation` produces the inline object assignment for each model in the constructor:

```typescript
function generateDelegateImplementation(p: {
  name: string
  lowerName: string
  pluralPath: string
}) {
  // Uses unique field as query param: /<pluralPath>/<id>
  return `    this.${p.lowerName} = {
      findMany: (options) =>
        this.#request('GET', '/${p.pluralPath}', undefined, options),
      findUnique: (where, options) =>
        this.#request('GET', \`/${p.pluralPath}/\${(where as any)[Object.keys(where)[0]]}\`, undefined, options),
      create: (data, options) =>
        this.#request('POST', '/${p.pluralPath}', data, options),
      update: (where, data, options) =>
        this.#request('PATCH', \`/${p.pluralPath}/\${(where as any)[Object.keys(where)[0]]}\`, data, options),
      delete: (where, options) =>
        this.#request('DELETE', \`/${p.pluralPath}/\${(where as any)[Object.keys(where)[0]]}\`, undefined, options),
    }`
}
```

The `(where as any)[Object.keys(where)[0]]` pattern extracts the value of whichever unique field is provided, since `WhereUniqueInput` may have `id`, or a custom unique field. This is a pragmatic approach for a generated REST client.

### 3. Generated Output Example

For a schema with:

```prisma
model User {
  id        Int      @id @default(autoincrement())
  email     String   @unique
  name      String?
  posts     Post[]
  createdAt DateTime @default(now())
}

model Post {
  id        Int      @id @default(autoincrement())
  title     String
  content   String?
  published Boolean  @default(false)
  author    User     @relation(fields: [authorId], references: [id])
  authorId  Int
}

enum Role {
  ADMIN
  USER
}
```

The generated `rest-client.ts` would contain:

```typescript
// Generated by @prisma/generator-rest-client — DO NOT EDIT

type RequestOptions = { headers?: Record<string, string>; signal?: AbortSignal }
type RestClientConfig = { baseUrl: string; headers?: Record<string, string>; fetch?: typeof globalThis.fetch }

export type Role = 'ADMIN' | 'USER'

export interface User {
  id: number
  email: string
  name?: string
  createdAt: string
}

export interface UserCreateInput {
  id?: number
  email: string
  name?: string
  createdAt?: string
}

export interface UserUpdateInput {
  email?: string
  name?: string
  createdAt?: string
}

export interface UserWhereUniqueInput {
  id?: number
  email?: string
}

// ... same pattern for Post ...

export interface UserDelegate {
  findMany(options?: RequestOptions): Promise<User[]>
  findUnique(where: UserWhereUniqueInput, options?: RequestOptions): Promise<User | null>
  create(data: UserCreateInput, options?: RequestOptions): Promise<User>
  update(where: UserWhereUniqueInput, data: UserUpdateInput, options?: RequestOptions): Promise<User>
  delete(where: UserWhereUniqueInput, options?: RequestOptions): Promise<User>
}

// ... PostDelegate ...

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>
  #fetch: typeof globalThis.fetch

  readonly user: UserDelegate
  readonly post: PostDelegate

  constructor(config: RestClientConfig) {
    // ... implementation ...
  }

  async #request<T>(method: string, path: string, body?: unknown, options?: RequestOptions): Promise<T> {
    // ... fetch wrapper ...
  }
}
```

Note that `posts` (the relation array on `User`) and `author` (the relation object on `Post`) are excluded from the interfaces since their `field.kind` is `'object'`. The `authorId` field on `Post` is included since it is a scalar field with `kind: 'scalar'` (even though `isReadOnly` is true for foreign key fields, it is still a scalar and relevant for the REST API).

### 4. Monorepo Integration Changes

#### 4.1 `tsconfig.build.bundle.json`

Add path mapping at line 42 (before the closing `}` of `paths`):

```json
"@prisma/generator-rest-client": ["./packages/generator-rest-client/src"]
```

This is required per AGENTS.md: "Add resolution path to `tsconfig.build.bundle.json` under `compilerOptions.paths` for go-to-definition to work in editors."

File: `/tsconfig.build.bundle.json`

#### 4.2 `.github/workflows/test-template.yml`

Add a test step in the `others` job (after the `credentials-store` step at line 866 or after `sqlcommenter-query-insights` at line 878):

```yaml
