import type { DatamodelEnum } from '@prisma/dmmf';
import type { GeneratorOptions } from '@prisma/generator';
import type { Model } from '@prisma/dmmf';

/** Generates the `RestClient` class that wires up all model delegates. */
export declare function generateClientClass(models: ReadonlyArray<Model>): string;

/** Generates a TypeScript union type for a Prisma enum. */
export declare function generateEnumType(enumDef: DatamodelEnum): string;

/** Generates a delegate interface with typed CRUD methods for a model. */
export declare function generateModelCrudMethods(model: Model): string;

/**
 * Generates four TypeScript interfaces for a model:
 * - `Model` — all scalar/enum fields
 * - `ModelCreateInput` — auto-generated fields become optional
 * - `ModelUpdateInput` — all fields optional, id fields excluded
 * - `ModelWhereUniqueInput` — only id and unique fields
 */
export declare function generateModelInterfaces(model: Model): string;

/** Generates the file header and shared helper types used by the REST client. */
export declare function generatePreamble(): string;

/** Maps a Prisma scalar type name to its TypeScript representation. */
export declare function mapPrismaScalarToTypeScript(prismaType: string): string;

/** `onGenerate` implementation — builds a typed REST client from the DMMF. */
export declare function onGenerate(options: GeneratorOptions): Promise<void>;

export { }

import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'string',
  BigInt: 'string',
  Decimal: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a Prisma scalar type name to its TypeScript representation. */
export function mapPrismaScalarToTypeScript(prismaType: string): string {
  return PRISMA_SCALAR_TO_TS[prismaType] ?? 'unknown'
}

/** Generates the file header and shared helper types used by the REST client. */
export function generatePreamble(): string {
  return `// Generated by @prisma/generator-rest-client — DO NOT EDIT

type RequestOptions = {
  headers?: Record<string, string>
  signal?: AbortSignal
}

type RestClientConfig = {
  baseUrl: string
  headers?: Record<string, string>
  fetch?: typeof globalThis.fetch
}`
}

/** Generates a TypeScript union type for a Prisma enum. */
export function generateEnumType(enumDef: DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

/**
 * Generates four TypeScript interfaces for a model:
 * - `Model` — all scalar/enum fields
 * - `ModelCreateInput` — auto-generated fields become optional
 * - `ModelUpdateInput` — all fields optional, id fields excluded
 * - `ModelWhereUniqueInput` — only id and unique fields
 */
export function generateModelInterfaces(model: Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')

  const mainInterface = renderInterface(model.name, scalarFields, { allOptional: false })

  const createInterface = renderInterface(`${model.name}CreateInput`, scalarFields, {
    allOptional: false,
    optionalOverride: (f) => isAutoGenerated(f),
  })

  const updateFields = scalarFields.filter((f) => !f.isId)
  const updateInterface = renderInterface(`${model.name}UpdateInput`, updateFields, { allOptional: true })

  const uniqueFields = scalarFields.filter((f) => f.isId || f.isUnique)
  const whereUniqueInterface = renderInterface(`${model.name}WhereUniqueInput`, uniqueFields, { allOptional: false })

  return [mainInterface, createInterface, updateInterface, whereUniqueInterface].join('\n\n')
}

/** Generates a delegate interface with typed CRUD methods for a model. */
export function generateModelCrudMethods(model: Model): string {
  const n = model.name
  return `export interface ${n}Delegate {
  findMany(options?: RequestOptions): Promise<${n}[]>
  findUnique(where: ${n}WhereUniqueInput, options?: RequestOptions): Promise<${n} | null>
  create(data: ${n}CreateInput, options?: RequestOptions): Promise<${n}>
  update(where: ${n}WhereUniqueInput, data: ${n}UpdateInput, options?: RequestOptions): Promise<${n}>
  delete(where: ${n}WhereUniqueInput, options?: RequestOptions): Promise<${n}>
}`
}

/** Generates the `RestClient` class that wires up all model delegates. */
export function generateClientClass(models: ReadonlyArray<Model>): string {
  const props = models.map((m) => {
    const lower = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    const plural = `${lower}s`
    return { typeName: m.name, propName: lower, path: plural, delegate: `${m.name}Delegate` }
  })

  const propertyDeclarations = props.map((p) => `  readonly ${p.propName}: ${p.delegate}`).join('\n')

  const delegateAssignments = props
    .map(
      (p) => `    this.${p.propName} = {
      findMany: (options) =>
        this.#request('GET', '/${p.path}', undefined, options),
      findUnique: (where, options) =>
        this.#request('GET', \`/${p.path}/\${extractId(where)}\`, undefined, options),
      create: (data, options) =>
        this.#request('POST', '/${p.path}', data, options),
      update: (where, data, options) =>
        this.#request('PATCH', \`/${p.path}/\${extractId(where)}\`, data, options),
      delete: (where, options) =>
        this.#request('DELETE', \`/${p.path}/\${extractId(where)}\`, undefined, options),
    }`,
    )
    .join('\n\n')

  return `function extractId(where: Record<string, unknown>): string {
  const value = Object.values(where)[0]
  return String(value)
}

export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>
  #fetch: typeof globalThis.fetch

${propertyDeclarations}

  constructor(config: RestClientConfig) {
    this.#baseUrl = config.baseUrl.replace(/\\/$/, '')
    this.#headers = config.headers ?? {}
    this.#fetch = config.fetch ?? globalThis.fetch.bind(globalThis)

${delegateAssignments}
  }

  async #request<T>(method: string, path: string, body?: unknown, options?: RequestOptions): Promise<T> {
    const response = await this.#fetch(\`\${this.#baseUrl}\${path}\`, {
      method,
      headers: {
        'Content-Type': 'application/json',
        ...this.#headers,
        ...options?.headers,
      },
      body: body ? JSON.stringify(body) : undefined,
      signal: options?.signal,
    })

    if (!response.ok) {
      throw new Error(\`REST client error: \${response.status} \${response.statusText}\`)
    }

    return response.json() as Promise<T>
  }
}`
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function resolveFieldType(field: Field): string {
  if (field.kind === 'enum') {
    return field.type
  }
  return mapPrismaScalarToTypeScript(field.type)
}

function isAutoGenerated(field: Field): boolean {
  return field.hasDefaultValue || field.isGenerated === true || field.isUpdatedAt === true
}

function renderInterface(
  name: string,
  fields: ReadonlyArray<Field>,
  opts: { allOptional: boolean; optionalOverride?: (f: Field) => boolean },
): string {
  const lines = fields.map((f) => {
    const tsType = resolveFieldType(f)
    const optional = opts.allOptional || !f.isRequired || opts.optionalOverride?.(f)
    const list = f.isList ? '[]' : ''
    return `  ${f.name}${optional ? '?' : ''}: ${tsType}${list}`
  })
  return `export interface ${name} {\n${lines.join('\n')}\n}`
}

import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import {
  generateClientClass,
  generateEnumType,
  generateModelCrudMethods,
  generateModelInterfaces,
  generatePreamble,
} from './template'

/** `onGenerate` implementation — builds a typed REST client from the DMMF. */
export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value ?? './generated/rest-client'
  const { datamodel } = options.dmmf

  const sections: string[] = []

  sections.push(generatePreamble())

  for (const enumDef of datamodel.enums) {
    sections.push(generateEnumType(enumDef))
  }

  for (const model of datamodel.models) {
    sections.push(generateModelInterfaces(model))
  }

  for (const model of datamodel.models) {
    sections.push(generateModelCrudMethods(model))
  }

  sections.push(generateClientClass(datamodel.models))

  const outputPath = path.resolve(outputDir, 'rest-client.ts')
  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(outputPath, sections.join('\n\n') + '\n')
}

import { generatorHandler } from '@prisma/generator-helper'

import { onGenerate } from './generator'

generatorHandler({
  onManifest() {
    return {
      defaultOutput: './generated/rest-client',
      prettyName: 'Prisma REST Client',
    }
  },
  onGenerate,
})
